        this.currentFormat = 'hex';
        this.hasHeaderSlot = false;
        this.hasHeaderActionsSlot = false;
        this.hasFooterSlot = false;
        this.hasFooterActionsSlot = false;
        this.triggerInputValue = '';
        this.isTriggerInputFocused = false;
        /**
         * The current color value (supports HEX and RGB formats)
         */
        this.value = '';
        /**
         * Displays a red asterisk (*) next to the label for visual emphasis.
         * @defaultValue false
         */
        this.showAsterisk = false;
        /**
         * If `true`, the user cannot modify the value.
         * @defaultValue false
         */
        this.readonly = false;
        /**
         * Indicates whether the input is in an invalid state
         * @defaultValue false
         */
        this.invalid = false;
        /**
         * Disables the color picker
         * @defaultValue false
         */
        this.disabled = false;
